                (success:Bool, error : NSError?) -> Void in
                
                // We pass the result of Face ID authentication to loginVC
                let loginVC = self.storyboard?.instantiateViewController(withIdentifier:"LoginVC") as? ViewController
                print("Face id Authentication \(success)")
                let appDelegate = UIApplication.shared.delegate as! AppDelegate
                if success == true{
                    appDelegate.isBiometricsEnabled = success
                    
                    // Store a flag indicating the user is authenticated.
                    UserDefaults.standard.set(true, forKey: "isUserAuthenticated")
                    
                }else {
                    print("Face ID Authentication failed")
                    let alertView = UIAlertController(title:"Warning", message:"You must enable Face Id to sign in with your account!", preferredStyle:.alert)
