            }
                
            , cancelBlock:{
                () -> Void in
                print("Face Id Authentication Cancelled")
            }, failBlock:{
                (error : NSError) -> Void in
                
                // Print the error on console if Face id authentication fails.
                print(error)
                
            })
        }
    }
    
